import React, { useState } from "react";

const base = {
  field: { marginBottom: "16px" },
  label: { display: "block", fontSize: "12px", fontWeight: 600, color: "#444", marginBottom: "5px", letterSpacing: ".3px" },
  optional: { fontWeight: 400, color: "var(--text-muted)" },
  input: {
    width: "100%", padding: "10px 12px",
    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
    fontSize: "14px", background: "var(--input-bg)", color: "var(--text-primary)",
    outline: "none", transition: "border .18s, box-shadow .18s", minHeight: "42px",
  },
  focus:  { border: "1px solid var(--brand)", boxShadow: "0 0 0 2px rgba(40,116,240,.12)" },
  error:  { border: "1px solid var(--error)" },
  errMsg: { fontSize: "11px", color: "var(--error)", marginTop: "4px" },
};

export default function FormField({ label, name, type = "text", value, onChange, error, optional = false, placeholder, children, style, inputStyle, ...rest }) {
  const [focused, setFocused] = useState(false);

  const inputStyle_ = {
    ...base.input,
    ...(error ? base.error : {}),
    ...(focused && !error ? base.focus : {}),
    ...inputStyle,
  };

  return (
    <div style={{ ...base.field, ...style }}>
      <label htmlFor={name} style={base.label}>
        {label}
        {optional && <span style={base.optional}> (optional)</span>}
      </label>
      {children || (
        <input id={name} name={name} type={type} value={value} placeholder={placeholder}
          onChange={(e) => onChange(e.target.value)}
          onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
          style={inputStyle_} {...rest} />
      )}
      {error && <p style={base.errMsg}>{error}</p>}
    </div>
  );
}
